const { execSync } = require('child_process');
const fs = require('fs');
const os = require('os');
const path = require('path');

// Read base64 PCM audio directly from the Gemini API JSON response
// (NOT from n8n's binary store, which is empty when binaryMode is "separate")
const base64Data = $('Generate Audio').item.json.candidates[0].content.parts[0].inlineData.data;

if (!base64Data) {
  throw new Error('No audio data received from Gemini TTS API');
}

const pcmBuffer = Buffer.from(base64Data, 'base64');

// Use the OS temp directory for intermediate files
const tmpDir = os.tmpdir();
const fileId = Date.now() + '-' + Math.random().toString(36).substring(7);
const inputFile = path.join(tmpDir, `${fileId}-in.pcm`);
const outputFile = path.join(tmpDir, `${fileId}-out.mp3`);

try {
  // 1. Write the PCM buffer to a temp file
  fs.writeFileSync(inputFile, pcmBuffer);

  // 2. Convert PCM to MP3 using FFmpeg with temp files (not pipes)
  //    -y overwrites output without prompting
  const command = `ffmpeg -y -f s16le -ar 24000 -ac 1 -i "${inputFile}" -codec:a libmp3lame -qscale:a 2 "${outputFile}"`;
  execSync(command, { stdio: 'pipe' });

  // 3. Read the resulting MP3 file
  const mp3Buffer = fs.readFileSync(outputFile);
  const mp3Base64 = mp3Buffer.toString('base64');

  // 4. Return the MP3 as binary data for the Upload node
  return [{
    json: { success: true, fileName: 'audio.mp3' },
    binary: {
      data: {
        data: mp3Base64,
        mimeType: 'audio/mpeg',
        fileName: 'audio.mp3'
      }
    }
  }];
} catch (error) {
  throw new Error('FFmpeg conversion failed: ' + error.message);
} finally {
  // 5. Clean up temp files
  try { fs.unlinkSync(inputFile); } catch (e) {}
  try { fs.unlinkSync(outputFile); } catch (e) {}
}

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  const now = new Date();
  const tomorrow = new Date(now.getTime() + 24 * 60 * 60 * 1000); // Add 1 day in ms
  item.json.timestamp = tomorrow.toISOString(); // Compatible with Supabase timestampz
}

return $input.all();

const { execSync } = require('child_process');

try {
  execSync('ffmpeg -version');
  return [{ json: { ffmpeg_status: "FFmpeg is installed" } }];
} catch (error) {
  return [{ json: { ffmpeg_status: "FFmpeg is NOT installed" } }];
}
